/*-----------------------------------------------------------------------------
 * MemoryMap
 *---------------------------------------------------------------------------*/

/*-----------------------------------------------------------------------------
 Examples of variable usage.
 1. Access to the entire register as a 32bit word:
        MemCtrl_s.ProgOtp_s.Timing_u.as_u32
        MemCtrl_s.DataOtp_s.Config_u.as_u32
        etc.
        ('as_u32' indicates the access to entire 32bit word)
 2. Access to bit fields:
        MemCtrl_s.ProgOtp_s.Timing_u.as_s.TwlcProg_u4
        MemCtrl_s.ProgOtp_s.Timing_u.as_s.TwhcProg_u14
        etc.
        ('as_s' indicates the access to a bit field in the structure)

 3. Shift to the single slices
        field_value = (value & [field]_MASK)>>[field]_SHIFT;
 *---------------------------------------------------------------------------*/


